// Shared variables (accessible by both processes
volatile int flag[2] = {0, 0};
volatile int turn;

// Process 0 entry section
void process_0_entry() {
    flag[0] = 1;        // P0 wants to enter
    turn = 1;          // Give priority to P1
    while (flag[1] && turn == 1);  // Wait if P1 wants in and it's P1's turn
}

// Process 0 exit section
void process_0_exit() {
    flag[0] = 0;        // P0 is done, no longer wants entry
}

// Similarly for Process 1:
// Process 1 entry: flag[1]=1; turn=0; while(flag[0] && turn==0);
// Process 1 exit: flag[1]=0;

import java.util.concurrent.atomic.AtomicBoolean;

public class LockExample {
    // Atomic boolean acts as the lock
    private static AtomicBoolean lock = new AtomicBoolean(false);

    // Shared counter for demonstration
    private static int counter = 0;

    public static void main(String[] args) throws InterruptedException {
        // Create multiple threads
        Thread[] threads = new Thread[5];
        for (int i = 0; i < 5; i++) {
            threads[i] = new Thread(new Worker(), "Thread-" + i);
            threads[i].start();
        }

        // Wait for all threads to complete
        for (Thread t : threads) {
            t.join();
        }

        System.out.println("Final counter value: " + counter);
    }

    static class Worker implements Runnable {
        @Override
        public void run() {
            // Entry section - acquire lock
            while (!lock.compareAndSet(false, true)) {
                // Lock was busy, try again (busy wait)
            }

            // Critical Section
            for (int i = 0; i < 1000; i++) {
                counter++;
            }

            // Exit section - release lock
            lock.set(false);
        }
    }
}

// SHARED VARIABLES
DECLARE choosing[1..N] : BOOLEAN    // Indicates process is choosing a ticket number
DECLARE number[1..N] : INTEGER      // Ticket number for each process

// INITIALIZATION
FOR i = 1 TO N DO
    choosing[i] = FALSE
    number[i] = 0
END FOR

// PROCESS i ENTRY SECTION
ENTRY_SECTION(i):
    choosing[i] = TRUE                       // Show that I'm choosing a number
    number[i] = max(number[1], ..., number[N]) + 1    // Get ticket (higher than all others)
    choosing[i] = FALSE                      // Finished choosing

    // Wait until it's my turn
    FOR j = 1 TO N DO
        WHILE choosing[j] = TRUE DO          // Wait while any process is choosing
            // busy wait
        END WHILE

        WHILE number[j] ≠ 0 AND (number[j] < number[i] OR (number[j] = number[i] AND j < i)) DO
            // Wait if j has valid ticket and goes before me
            // busy wait
        END WHILE
    END FOR

// CRITICAL SECTION
// Only one process can be here at a time

// PROCESS i EXIT SECTION
EXIT_SECTION(i):
    number[i] = 0                             // Give up my ticket

